    b_bin = format(b, 'b')
    max_len = max(len(a_bin), len(b_bin))
    a_bin, b_bin = a_bin.zfill(max_len), b_bin.zfill(max_len)
    return '0b' + ''.join('1' if (ca == '1' or cb == '1') else '0' for ca, cb in zip(a_bin, b_bin))

if __name__ == "__main__":
    print(f"1 OR 0: {binary_or(1, 0)}")
